      "file": "10-Film and Cognition_ A Critical Review of Current Theory.pdf",
      "title": "Film and Cognition: A Critical Review of Current Theory",
      "year": 1984,
      "doi": "10.1080/00393541.1984.11650364",
      "pageCount": 10,
      "articleViews": 6,
      "citingArticlesPdf": null,
